triggers.customTriggerLogic:
function()
    local isIconDisplayed = true;
    for auraIndex = 1, GetNumShapeshiftForms() do
        local _,name,isActive = GetShapeshiftFormInfo(auraIndex);
        if isActive and (("Battle Stance" == name) or ("Defensive Stance" == name) or ("Berserker Stance" == name)) then
            isIconDisplayed = false;
        end
    end
    return isIconDisplayed;
end

