function()
    local hasMainHandEnchant, mainHandExpiration, mainHandCharges, hasOffHandEnchant, offHandExpiration, offHandCharges = GetWeaponEnchantInfo();

    if (null == GetInventoryItemID("player", 17)) then
        return (1 ~= hasMainHandEnchant);
    else
        return ((1 ~= hasMainHandEnchant) or (1 ~= hasOffHandEnchant));
    end
end

